}

interface WorkflowFailure {
  outcome: "blocked";
  errors: CliError[];
}

interface PromptExecutionSuccess {
  outcome: ProviderPayload["outcome"];
  sessionId: string;
  payload: ProviderPayload;
}

interface PromptExecutionFailure {
  outcome: "blocked";
